public interface Callback {
    void onComplete();
}
public void executeWithCallback(Callback callback) {
    callback.onComplete();
}
executeWithCallback(() -> System.out.println("done"));

CREATE PROCEDURE ExecuteWithCallback @result NVARCHAR(MAX) OUTPUT AS
BEGIN
    WAITFOR DELAY '00:00:01';
    SET @result = 'done';
END;
DECLARE @output NVARCHAR(MAX);
EXEC ExecuteWithCallback @output OUTPUT;
SELECT @output;
